mapper.select:
select id, title, message_type, receiver_type, send_status, send_time, created_at, updated_at, created_by, updated_by, deleted from admin_messages
and deleted = false
and title like concat('%', #{keyword}, '%')
and send_status = #{sendStatus}
order by id desc limit #{pageSize} offset #{offset}

mapper.insert:
insert into admin_messages (
  title, message_type, receiver_type, send_status, send_time,
  created_at, updated_at, created_by, updated_by, deleted
)
values (
  #{title}, #{messageType}, #{receiverType}, #{sendStatus}, #{sendTime},
  #{createdAt}, #{updatedAt}, #{createdBy}, #{updatedBy}, #{deleted}
)

mapper.update:
update admin_messages
set deleted = true,
    updated_at = #{updatedAt},
    updated_by = #{updatedBy}
where id = #{id}
  and deleted = false
